// Generated by `db pull`. Safe to edit — re-pull will not overwrite this file.
import { Database, fromExisting } from '@aws-blocks/bb-data';
import { readFileSync } from 'node:fs';
import { tableMeta, type TableMeta } from './database.meta.js';
import { DATABASE_CA_CERT } from './database.ca.js';
import { Scope } from '@aws-blocks/core';
import { AppSetting } from '@aws-blocks/bb-app-setting';
import { dbConnectionParameterName } from '@aws-blocks/core/db-naming';

const scope = new Scope('supabase');

const dbParameterName = process.env.BLOCKS_SSM_PARAM_DB_URL
  ?? dbConnectionParameterName(process.env.BLOCKS_STAGE ?? 'sandbox');
const dbUrl = AppSetting.fromExisting(scope, 'db-url', { name: dbParameterName, secret: true });

async function resolveConnString(): Promise<string> {
  const raw = await dbUrl.get();
  let u: URL;
  try {
    u = new URL(raw);
  } catch {
    // Not URL-parseable (e.g. an unencoded password) — pg can still parse it.
    // Skip port normalization rather than crash; set the port in your stored
    // connection string if you need a specific one.
    return raw;
  }
  if (process.env.BLOCKS_STACK_NAME) {
    u.port = '6543';
    u.searchParams.set('prepared_statements', 'false');
  } else {
    u.port = '5432';
  }
  // Strip sslmode so resolveDbSsl()'s CA pin takes effect: node pg ignores a
  // programmatic ssl.ca and verifies against the system trust store when
  // sslmode is present in the URL.
  u.searchParams.delete('sslmode');
  return u.toString();
}

function resolveDbSsl(): { ca?: string; rejectUnauthorized: boolean } {
  // DATABASE_CA_CERT (inline PEM or a file path) overrides the committed cert.
  const envCa = process.env.DATABASE_CA_CERT;
  const ca = envCa
    ? (envCa.includes('-----BEGIN') ? envCa : readFileSync(envCa, 'utf8'))
    : (DATABASE_CA_CERT || undefined);
  if (ca) {
    // Pin the provider CA → fully verified (sslmode=verify-full equivalent).
    return { ca, rejectUnauthorized: true };
  }
  // ⚠️ No CA available: the connection is encrypted but the server certificate is
  // NOT verified (no man-in-the-middle protection). Download your Supabase CA
  // ('prod-ca-2021.crt' from Database Settings → SSL Configuration) and re-run
  // `npx bb-data pull` to capture it (or set DATABASE_CA_CERT). See MIGRATION_GUIDE.md.
  return { rejectUnauthorized: false };
}

/**
 * Database instance connected to your Supabase Postgres.
 *
 * RLS caveat: db.crud() (via supabaseCrud()) always enforces RLS.
 * Raw db.query() / db.execute() / db.transaction() BYPASS RLS.
 * For hand-written queries, use db.withRLS({ userId }) to enforce
 * row-level security — otherwise all rows are visible.
 */
export const db = new Database(scope, 'db', {
  connection: fromExisting({ connectionString: { get: resolveConnString }, ssl: resolveDbSsl() }),
  rlsPolicy: 'enforce',
  schema: tableMeta,
});

/** Spread this into your ApiNamespace to add CRUD handlers. */
export function supabaseCrud(context: any, auth?: { requireAuth: (ctx: any) => Promise<{ userId: string }> }) {
  return db.crud<TableMeta>({
    tables: Object.keys(tableMeta) as (keyof typeof tableMeta)[],
    auth: () => {
      if (!auth) throw new Error('Auth not configured — pass auth to supabaseCrud(). See MIGRATION_GUIDE.md#auth');
      return auth.requireAuth(context);
    },
  });
}
